#include <torch/extension.h>
#include <immintrin.h>
#include <omp.h>
#include <cmath>
#include <algorithm>
#include <vector>

// AVX512内核实现 - 使用512位向量(16个float32)
inline void compute_attention_block_avx512(
    const float* __restrict__ q_ptr,
    const float* __restrict__ k_ptr,
    const float* __restrict__ v_ptr,
    float* __restrict__ out_ptr,
    int64_t L, int64_t D,
    float sm_scale
) {
    // 为每个query位置计算注意力
    for (int64_t i = 0; i < L; ++i) {
        // 获取当前query向量
        const float* q_i = q_ptr + i * D;

        // 计算Q_i * K^T for all j
        std::vector<float> scores(L);

        // 计算scores并找到最大值用于数值稳定
        float max_score = -INFINITY;

        #pragma omp parallel for reduction(max:max_score)
        for (int64_t j = 0; j < L; ++j) {
            const float* k_j = k_ptr + j * D;
            float dot_product = 0.0f;

            // 使用AVX512向量化点积计算
            int64_t d = 0;
            if (D >= 16) {
                __m512 sum_vec = _mm512_setzero_ps();
                for (; d + 16 <= D; d += 16) {
                    __m512 q_vec = _mm512_loadu_ps(q_i + d);
                    __m512 k_vec = _mm512_loadu_ps(k_j + d);
                    sum_vec = _mm512_fmadd_ps(q_vec, k_vec, sum_vec);  // FMA: a*b + c
                }
                // 水平求和
                dot_product += _mm512_reduce_add_ps(sum_vec);
            }

            // 处理剩余元素
            for (; d < D; ++d) {
                dot_product += q_i[d] * k_j[d];
            }

            scores[j] = dot_product * sm_scale;
            if (scores[j] > max_score) {
                max_score = scores[j];
            }
        }

        // 应用softmax
        float exp_sum = 0.0f;
        #pragma omp parallel for reduction(+:exp_sum)
        for (int64_t j = 0; j < L; ++j) {
            scores[j] = std::exp(scores[j] - max_score);
            exp_sum += scores[j];
        }

        float inv_exp_sum = 1.0f / exp_sum;

        // 计算输出: out_i = Σ_j(softmax_j * V_j)
        float* out_i = out_ptr + i * D;

        // 初始化输出向量为0
        if (D >= 16) {
            for (int64_t d = 0; d + 16 <= D; d += 16) {
                _mm512_storeu_ps(out_i + d, _mm512_setzero_ps());
            }
        }
        for (int64_t d = (D / 16) * 16; d < D; ++d) {
            out_i[d] = 0.0f;
        }

        // 累加加权value
        for (int64_t j = 0; j < L; ++j) {
            float weight = scores[j] * inv_exp_sum;
            const float* v_j = v_ptr + j * D;

            // AVX512向量化累加
            int64_t d = 0;
            if (D >= 16) {
                __m512 weight_vec = _mm512_set1_ps(weight);
                for (; d + 16 <= D; d += 16) {
                    __m512 v_vec = _mm512_loadu_ps(v_j + d);
                    __m512 out_vec = _mm512_loadu_ps(out_i + d);
                    __m512 weighted_v = _mm512_mul_ps(weight_vec, v_vec);
                    out_vec = _mm512_add_ps(out_vec, weighted_v);
                    _mm512_storeu_ps(out_i + d, out_vec);
                }
            }

            // 处理剩余元素
            for (; d < D; ++d) {
                out_i[d] += weight * v_j[d];
            }
        }
    }
}

// AVX2内核实现 - 后备方案
inline void compute_attention_block_avx2(
    const float* __restrict__ q_ptr,
    const float* __restrict__ k_ptr,
    const float* __restrict__ v_ptr,
    float* __restrict__ out_ptr,
