cpp_source = """
#include <torch/extension.h>
#include <immintrin.h>
#include <omp.h>
#include <cmath>
#include <algorithm>

// AVX512内核实现 - 使用512位向量(16个float32)
inline void compute_attention_block_avx512(
    const float* __restrict__ q_ptr,
    const float* __restrict__ k_ptr,
    const float* __restrict__ v_ptr,
    float* __restrict__ out_ptr,
    int64_t L, int64_t D,
    float sm_scale
) {
    // 为每个query位置计算注意力
    for (int64_t i = 0; i < L; ++i) {
        // 获取当前query向量
        const float* q_i = q_ptr + i * D;

        // 计算Q_i * K^T for all j
        float* scores = (float*)alloca(L * sizeof(float));

        // 计算scores并找到最大值用于数值稳定
        float max_score = -INFINITY;

        #pragma omp parallel for reduction(max:max_score)
        for (int64_t j = 0; j < L; ++j) {
            const float* k_j = k_ptr + j * D;
            float dot_product = 0.0f;

            // 使用AVX512向量化点积计算
            int64_t d = 0;
            if (D >= 16) {
                __m512 sum_vec = _mm512_setzero_ps();
                for (; d + 16 <= D; d += 16) {
                    __m512 q_vec = _mm512_loadu_ps(q_i + d);
                    __m512 k_vec = _mm512_loadu_ps(k_j + d);
                    sum_vec = _mm512_fmadd_ps(q_vec, k_vec, sum_vec);  // FMA: a*b + c
                }
                // 水平求和
                dot_product += _mm512_reduce_add_ps(sum_vec);
            }

            // 处理剩余元素
            for (; d < D; ++d) {
                dot_product += q_i[d] * k_j[d];
            }

            scores[j] = dot_product * sm_scale;
            if (scores[j] > max_score) {
                max_score = scores[j];
            }
        }

        // 应用softmax
        float exp_sum = 0.0f;
        #pragma omp parallel for reduction(+:exp_sum)
        for (int64_t j = 0; j < L; ++j) {
            scores[j] = std::exp(scores[j] - max_score);
            exp_sum += scores[j];
        }

        float inv_exp_sum = 1.0f / exp_sum;

        // 计算输出: out_i = Σ_j(softmax_j * V_j)
        float* out_i = out_ptr + i * D;

        // 初始化输出向量为0
        if (D >= 16) {
            for (int64_t d = 0; d + 16 <= D; d += 16) {
                _mm512_storeu_ps(out_i + d, _mm512_setzero_ps());
            }
        }
        for (int64_t d = (D / 16) * 16; d < D; ++d) {
            out_i[d] = 0.0f;
        }

        // 累加加权value
        for (int64_t j = 0; j < L; ++j) {
            float weight = scores[j] * inv_exp_sum;
            const float* v_j = v_ptr + j * D;

            // AVX512向量化累加
            int64_t d = 0;
            if (D >= 16) {
                __m512 weight_vec = _mm512_set1_ps(weight);
                for (; d + 16 <= D; d += 16) {
                    __m512 v_vec = _mm512_loadu_ps(v_j + d);
                    __m512 out_vec = _mm512_loadu_ps(out_i + d);
                    __m512 weighted_v = _mm512_mul_ps(weight_vec, v_vec);
                    out_vec = _mm512_add_ps(out_vec, weighted_v);
                    _mm512_storeu_ps(out_i + d, out_vec);
                }
            }

            // 处理剩余元素
            for (; d < D; ++d) {
                out_i[d] += weight * v_j[d];
            }
        }
    }
}

// AVX2内核实现 - 后备方案
inline void compute_attention_block_avx2(
    const float* __restrict__ q_ptr,
    const float* __restrict__ k_ptr,
    const float* __restrict__ v_ptr,
    float* __restrict__ out_ptr,
    int64_t L, int64_t D,
    float sm_scale
) {
    // 为每个query位置计算注意力
    for (int64_t i = 0; i < L; ++i) {
        const float* q_i = q_ptr + i * D;
        float* scores = (float*)alloca(L * sizeof(float));
        float max_score = -INFINITY;

        #pragma omp parallel for reduction(max:max_score)
        for (int64_t j = 0; j < L; ++j) {
            const float* k_j = k_ptr + j * D;
            float dot_product = 0.0f;

            // AVX2向量化点积
            int64_t d = 0;
            if (D >= 8) {
                __m256 sum_vec = _mm256_setzero_ps();
                for (; d + 8 <= D; d += 8) {
                    __m256 q_vec = _mm256_loadu_ps(q_i + d);
                    __m256 k_vec = _mm256_loadu_ps(k_j + d);
                    sum_vec = _mm256_fmadd_ps(q_vec, k_vec, sum_vec);
                }
                // 水平求和
                alignas(32) float sum_arr[8];
                _mm256_store_ps(sum_arr, sum_vec);
                for (int k = 0; k < 8; ++k) {
                    dot_product += sum_arr[k];
                }
            }

            for (; d < D; ++d) {
                dot_product += q_i[d] * k_j[d];
            }

            scores[j] = dot_product * sm_scale;
            if (scores[j] > max_score) {
                max_score = scores[j];
            }
        }

        float exp_sum = 0.0f;
        #pragma omp parallel for reduction(+:exp_sum)
        for (int64_t j = 0; j < L; ++j) {
            scores[j] = std::exp(scores[j] - max_score);
            exp_sum += scores[j];
        }

        float inv_exp_sum = 1.0f / exp_sum;
        float* out_i = out_ptr + i * D;

        // 初始化输出
        if (D >= 8) {
            for (int64_t d = 0; d + 8 <= D; d += 8) {
                _mm256_storeu_ps(out_i + d, _mm256_setzero_ps());
            }
        }
        for (int64_t d = (D / 8) * 8; d < D; ++d) {
            out_i[d] = 0.0f;
        }

        // 累加
        for (int64_t j = 0; j < L; ++j) {
            float weight = scores[j] * inv_exp_sum;
            const float* v_j = v_ptr + j * D;

            int64_t d = 0;
            if (D >= 8) {
                __m256 weight_vec = _mm256_set1_ps(weight);
                for (; d + 8 <= D; d += 8) {
                    __m256 v_vec = _mm256_loadu_ps(v_j + d);
                    __m256 out_vec = _mm256_loadu_ps(out_i + d);
                    __m256 weighted_v = _mm256_mul_ps(weight_vec, v_vec);
                    out_vec = _mm256_add_ps(out_vec, weighted_v);
                    _mm256_storeu_ps(out_i + d, out_vec);
                }
            }

            for (; d < D; ++d) {
                out_i[d] += weight * v_j[d];
            }
        }
    }
}

// 主kernel函数
torch::Tensor akg_cache_attention_medium_longseq_kernel(
    torch::Tensor query,
    torch::Tensor key,
    torch::Tensor value,
    float sm_scale
) {
    // 检查输入
    TORCH_CHECK(query.device().is_cpu(), "Input must be on CPU");
    TORCH_CHECK(query.dim() == 4, "Query must be 4D tensor [B, H, L, D]");
    TORCH_CHECK(key.dim() == 4, "Key must be 4D tensor [B, H, L, D]");
    TORCH_CHECK(value.dim() == 4, "Value must be 4D tensor [B, H, L, D]");

    // 确保张量连续
    if (!query.is_contiguous()) query = query.contiguous();
    if (!key.is_contiguous()) key = key.contiguous();
    if (!value.is_contiguous()) value = value.contiguous();

    // 获取形状参数
    auto B = query.size(0);
    auto H = query.size(1);
    auto L = query.size(2);
    auto D = query.size(3);

    // 验证key和value的形状
    TORCH_CHECK(key.size(0) == B && key.size(1) == H && key.size(2) == L && key.size(3) == D,
                "Key shape must match query");
    TORCH_CHECK(value.size(0) == B && value.size(1) == H && value.size(2) == L && value.size(3) == D,
                "Value shape must match query");

    // 创建输出张量
    torch::Tensor output = torch::empty({B, H, L, D}, query.options());

    // 获取数据指针
    auto q_ptr = query.data_ptr<float>();
    auto k_ptr = key.data_ptr<float>();
    auto v_ptr = value.data_ptr<float>();
    auto out_ptr = output.data_ptr<float>();

    // 检查AVX512支持并选择合适的实现
    #ifdef __AVX512F__
    bool use_avx512 = true;
    #else
    bool use_avx512 = false;
    #endif

    // 并行处理批次和头
    #pragma omp parallel for collapse(2)
    for (int64_t b = 0; b < B; ++b) {
        for (int64_t h = 0; h < H; ++h) {
            // 计算每个头在当前批次中的偏移
            int64_t bh_offset = (b * H + h) * L * D;

            const float* q_bh = q_ptr + bh_offset;
            const float* k_bh = k_ptr + bh_offset;
            const float* v_bh = v_ptr + bh_offset;
            float* out_bh = out_ptr + bh_offset;

            if (use_avx512) {
                compute_attention_block_avx512(q_bh, k_bh, v_bh, out_bh, L, D, sm_scale);
            } else {
                compute_attention_block_avx2(q_bh, k_bh, v_bh, out_bh, L, D, sm_scale);
            }
        }
    }

    return output;
}

