        if key.device.type != "cpu":
            key = key.cpu()
        if value.device.type != "cpu":
            value = value.cpu()

        # 调用C++ kernel
        return akg_cache_attention_module.akg_cache_attention_medium_longseq_kernel(query, key, value, self.sm_scale)


